  192 /// Dispatch `ciabatta todo`:
  193 ///   - a TASK string adds the task and exits
  194 ///   - `-d` spawns a detached copy that serves the web app in the background
  195 ///   - otherwise serve the web app in the foreground until Ctrl-C
  196 async fn cmd_todo(task: Option<String>, detach: bool, port: u16, ai_port: u16) -> Result<()> {
  197     let store = std::sync::Arc::new(todo::Store::open()?);
