  199     if let Some(text) = task {
  200         let added = store.add(&text)?;
  201         println!("Added task #{}: {}", added.id, added.text);
  202         return Ok(());
  203     }
  204 
  205     if detach {
  206         spawn_detached_todo(port, ai_port)?;
  207         println!("Todo app started in the background at http://127.0.0.1:{port}");
  208         println!("Stop it with: pkill -f 'ciabatta todo'");
  209         return Ok(());
  210     }
  211 
  212     todo::server::serve(store, port, ai_port).await
