  215 /// Dispatch `ciabatta ai`:
  216 ///   - no subcommand: the chat TUI plus the live mind-map server
  217 ///   - `setup`: interactively write the [ai] config section
  218 ///   - `ask PROMPT…`: one-shot question, plain output
  219 ///   - `serve`: just the daemon (mind map + JSON API)
  220 ///
  221 /// Like `configure`, this works before the project is initialized: it prefers
  222 /// an existing .ciabatta root and otherwise targets the current directory
  223 /// (setup/first use creates .ciabatta/ai/ as needed).
  224 async fn cmd_ai(
  225     subcommand: Option<AiCommand>,
  226     port: u16,
  227     no_graph: bool,
  228     mode: String,
  229     continue_last: bool,
  230 ) -> Result<()> {
  231     let cwd = env::current_dir().context("Failed to get current directory")?;
  232     let root = find_root(&cwd).unwrap_or(cwd);
  233 
  234     if let Some(AiCommand::Setup) = subcommand {
  235         return ai::run_setup(&root);
  236     }
  237 
  238     let mode = ai::Mode::parse(&mode)?;
  239     let cfg = load_config(&root)?;
  240     if cfg.ai.is_none() {
  241         eprintln!("note: no [ai] section in ciabatta.toml — run `ciabatta ai setup` to configure");
  242         eprintln!("      a provider (Claude, an OpenAI-compatible endpoint, or vLLM). Trying defaults…\n");
  243     }
  244 
  245     // `--continue` resumes the latest conversation for the TUI and one-shot ask.
  246     let resume = if continue_last { ai::Resume::Latest } else { ai::Resume::None };
  247 
  248     match subcommand {
  249         None => ai::run_tui(&root, &cfg, port, no_graph, mode, resume).await,
  250         Some(AiCommand::Serve) => ai::run_serve(&root, &cfg, port, mode).await,
  251         Some(AiCommand::Resume { id }) => {
  252             ai::run_resume(&root, &cfg, port, no_graph, mode, id).await
  253         }
  254         Some(AiCommand::Report { days }) => ai::run_report(&root, &cfg, days, mode).await,
  255         Some(AiCommand::Delete { id }) => ai::run_delete(&root, &id),
  256         Some(AiCommand::Clear { yes }) => ai::run_clear(&root, yes),
  257         Some(AiCommand::Ship { task, todo }) => {
  258             // The task text is either given inline or pulled from a todo.
  259             let prompt = if let Some(id) = todo {
  260                 let store = todo::Store::open()?;
  261                 let text = store
  262                     .text_of(id)
  263                     .with_context(|| format!("no todo #{id} — see `ciabatta todo`"))?;
  264                 if !task.is_empty() {
  265                     // Allow appending extra guidance after --todo.
  266                     format!("{text}\n\n{}", task.join(" "))
  267                 } else {
  268                     text
  269                 }
  270             } else {
  271                 let p = task.join(" ");
  272                 if p.trim().is_empty() {
  273                     bail!("Nothing to ship. Usage: ciabatta ai ship <task>  (or --todo <id>)");
  274                 }
  275                 p
  276             };
  277             ai::run_ship(&root, &cfg, &prompt, todo).await
  278         }
  279         Some(AiCommand::Jobs) => ai::run_jobs(&root, &cfg),
  280         Some(AiCommand::Ask { prompt }) => {
  281             ai::run_ask(&root, &cfg, &prompt.join(" "), mode, resume).await
  282         }
  283         Some(AiCommand::BurnIn { review, limit }) => {
  284             ai::run_burn_in(&root, &cfg, port, review, limit).await
  285         }
  286         Some(AiCommand::Setup) => unreachable!("handled above"),
  287     }
  288 }
