  290 /// Dispatch `ciabatta watch <command>`: run the command through the shell,
  291 /// capturing its output into a searchable, live web view. Bookmarks and triggers
  292 /// persist to disk keyed by the command, so they survive restarts.
  293 async fn cmd_watch(
  294     command: Vec<String>,
  295     triggers: Vec<String>,
  296     max_lines: usize,
  297     port: u16,
  298     no_open: bool,
  299 ) -> Result<()> {
  300     let command = command.join(" ");
  301     if command.trim().is_empty() {
  302         bail!("No command given. Usage: ciabatta watch <command>");
  303     }
  304 
  305     let store = std::sync::Arc::new(watch::WatchState::new(&command, max_lines)?);
  306     // Seed any -t triggers from the command line (deduped against persisted ones).
  307     for phrase in &triggers {
  308         store.add_trigger(phrase, false)?;
  309     }
  310 
  311     watch::server::serve(store, command, port, !no_open).await
  312 }
