  314 /// Re-launch this executable as a detached background process serving the todo
  315 /// web app (`ciabatta todo --port <port>`), with its stdio discarded so it
  316 /// keeps running after this process exits.
  317 fn spawn_detached_todo(port: u16, ai_port: u16) -> Result<()> {
  318     use std::process::{Command, Stdio};
  319 
  320     let exe = env::current_exe().context("Failed to locate the ciabatta executable")?;
  321     Command::new(exe)
  322         .arg("todo")
  323         .arg("--port")
  324         .arg(port.to_string())
  325         .arg("--ai-port")
  326         .arg(ai_port.to_string())
  327         .stdin(Stdio::null())
  328         .stdout(Stdio::null())
  329         .stderr(Stdio::null())
  330         .spawn()
  331         .context("Failed to start the background todo app")?;
  332     Ok(())
  333 }
