  335 /// Initialize the `tracing` subscriber for stderr logging.
  336 ///
  337 /// Debug logging turns on when the `--debug` flag is passed OR the
  338 /// `CIABATTA_DEBUG` environment variable is set to any non-empty value other
  339 /// than `0`/`false`. For finer-grained control the `CIABATTA_LOG` environment
  340 /// variable is honored directly as a `tracing` env-filter (e.g.
  341 /// `CIABATTA_LOG=ciabatta=trace`), overriding the flag-derived default.
  342 fn init_logging(debug_flag: bool) {
  343     use tracing_subscriber::{EnvFilter, fmt};
  344 
  345     let debug = debug_flag
  346         || env::var("CIABATTA_DEBUG")
  347             .map(|v| {
  348                 let v = v.trim();
  349                 !v.is_empty() && v != "0" && !v.eq_ignore_ascii_case("false")
  350             })
  351             .unwrap_or(false);
  352 
  353     let default_directive = if debug {
  354         "ciabatta=debug"
  355     } else {
  356         "ciabatta=warn"
  357     };
  358     let filter = EnvFilter::try_from_env("CIABATTA_LOG")
  359         .unwrap_or_else(|_| EnvFilter::new(default_directive));
  360 
  361     // Best-effort: ignore the error if a subscriber is somehow already set.
  362     let _ = fmt()
  363         .with_env_filter(filter)
  364         .with_target(false)
  365         .with_writer(std::io::stderr)
  366         .try_init();
  367 }
