  384 fn load_project(config_path: Option<&std::path::Path>) -> Result<(PathBuf, CiabattaConfig)> {
  385     let cwd = env::current_dir().context("Failed to get current directory")?;
  386 
  387     if let Some(p) = config_path {
  388         // Explicit path: load exactly this file, and derive the project root
  389         // (used to resolve relative recipe paths) from its location.
  390         let cfg = load_config_file(p)?;
  391         let root = resolve_root_for_config(p, &cwd);
  392         Ok((root, cfg))
  393     } else {
  394         // Walk upward from cwd until a .ciabatta/ directory is found.
  395         let root = find_root(&cwd).ok_or_else(|| {
  396             anyhow::anyhow!(
  397                 "No .ciabatta/ directory found in '{}' or any parent directory.\n\
  398                  Create one and add a ciabatta.toml to get started.\n\
  399                  Run `ciabatta config reference` for format documentation.",
  400                 cwd.display()
  401             )
  402         })?;
  403         let cfg = load_config(&root)?;
  404         Ok((root, cfg))
  405     }
  406 }
