  408 /// Determine the project root for an explicit `--config` file: normalize it to
  409 /// an absolute path, then apply [`root_from_config_path`]. Falls back to `cwd`
  410 /// when the file has no usable parent.
  411 fn resolve_root_for_config(config_path: &Path, cwd: &Path) -> PathBuf {
  412     let abs = std::fs::canonicalize(config_path).unwrap_or_else(|_| cwd.join(config_path));
  413     root_from_config_path(&abs).unwrap_or_else(|| cwd.to_path_buf())
  414 }
