  416 /// Derive the project root from an absolute config-file path. When the file
  417 /// lives in a `.ciabatta/` directory (the standard layout) the root is the
  418 /// directory that contains `.ciabatta`; otherwise it's the file's own parent
  419 /// directory, so relative recipe paths resolve alongside the config.
  420 fn root_from_config_path(config_abs: &Path) -> Option<PathBuf> {
  421     let parent = config_abs.parent()?;
  422     if parent.file_name() == Some(std::ffi::OsStr::new(config::CIABATTA_DIR)) {
  423         Some(parent.parent().unwrap_or(parent).to_path_buf())
  424     } else {
  425         Some(parent.to_path_buf())
  426     }
  427 }
