  429 /// Build the final environment variable map:
  430 /// 1. Start with the current process env
  431 /// 2. Merge CIABATTA_* vars from local git (`--local`) or the configured CI
  432 /// 3. Override with CLI -e flags (highest priority)
  433 /// 4. Derive CIABATTA_PATH
  434 ///
  435 /// When `announce` is true the resolved variables are echoed to stderr; callers
  436 /// that hand off to the TUI pass `false`, since that output would corrupt the
  437 /// alternate screen.
  438 fn build_env_vars(
  439     cfg: &CiabattaConfig,
  440     cli_env: &[String],
  441     local: bool,
  442     root: &Path,
  443     announce: bool,
  444 ) -> Result<HashMap<String, String>> {
  445     let mut vars: HashMap<String, String> = std::env::vars().collect();
  446 
  447     // Local mode is selected by the `--local` flag OR by `CIABATTA_ENV=local`.
  448     let env = CiabattaEnv::detect_with_flag(local);
  449 
  450     if env.is_local() {
  451         // Local development: resolve build variables from git history. These
  452         // take precedence over any stale ambient CIABATTA_* in the environment.
  453         let git_vars = env.resolve_vars(root)?;
  454         if announce && !git_vars.is_empty() {
  455             eprintln!("CIABATTA variables resolved from local git:");
  456             for (k, v) in sorted(&git_vars) {
  457                 eprintln!("  {k} = {v}");
  458             }
  459         }
  460         vars.extend(git_vars);
  461         // Record the mode so the runner (pull best-hash fallback) and any child
  462         // processes see it, even when it was turned on by the `--local` flag.
  463         vars.insert(
  464             environment::ENV_VAR.to_string(),
  465             environment::LOCAL.to_string(),
  466         );
  467     } else if let Some(ref system) = cfg.system
  468         && let Some(ref ci_name) = system.ci
  469     {
  470         // Resolve CI variables and (optionally) print them.
  471         let ci_system = ci::CiSystem::from(ci_name.as_str());
  472         let (ci_vars, resolved) = ci::resolve_ci_vars(&ci_system);
  473         if announce && !resolved.is_empty() {
  474             eprintln!("CI variables resolved from {}:", ci_system);
  475             for rv in &resolved {
  476                 eprintln!(
  477                     "  {} = {} (from {})",
  478                     rv.ciabatta_name, rv.value, rv.source_name
  479                 );
  480             }
  481         }
  482         // Merge CI vars; they DON'T override existing env vars set by the user.
  483         for (k, v) in ci_vars {
  484             vars.entry(k).or_insert(v);
  485         }
  486     }
  487 
  488     // CLI -e flags override everything.
  489     let cli_map = cli::parse_env_flags(cli_env)?;
  490     vars.extend(cli_map);
  491 
  492     // Derive CIABATTA_PATH from the now-fully-resolved variables, unless the
  493     // user set it explicitly (via -e or the environment).
  494     if let Some(path) = derive_ciabatta_path(&vars) {
  495         vars.entry("CIABATTA_PATH".to_string()).or_insert(path);
  496     }
  497 
  498     if tracing::enabled!(tracing::Level::DEBUG) {
  499         for (k, v) in sorted(&vars) {
  500             if k.starts_with("CIABATTA_") {
  501                 tracing::debug!(var = %k, value = %v, "resolved ciabatta variable");
  502             }
  503         }
  504     }
  505 
  506     Ok(vars)
  507 }
