  509 /// Compute the `CIABATTA_PATH` convenience variable:
  510 ///   - a tag (CLI/env `CIABATTA_TAG`) wins → `/{CIABATTA_TAG}/`
  511 ///   - otherwise → `/{CIABATTA_BRANCH}/{CIABATTA_COMMIT}`
  512 ///
  513 /// Returns `None` when there isn't enough information to build it (no tag and no
  514 /// branch), so callers leave `CIABATTA_PATH` unset rather than emitting `//`.
  515 fn derive_ciabatta_path(vars: &HashMap<String, String>) -> Option<String> {
  516     let non_empty = |key: &str| vars.get(key).filter(|v| !v.is_empty()).cloned();
  517 
  518     if let Some(tag) = non_empty("CIABATTA_TAG") {
  519         return Some(format!("/{tag}/"));
  520     }
  521     let branch = non_empty("CIABATTA_BRANCH")?;
  522     let commit = non_empty("CIABATTA_COMMIT").unwrap_or_default();
  523     Some(format!("/{branch}/{commit}"))
  524 }
